query GetCampaignPerformance($first: Int) {
  pacingDataObjectsConnection(first: $first) {
    edges {
      node {
        id
        campaignName
        totalImpressions
        impressionGoal
        impressionsToday
        impressionsYesterday
        ctr
        roas
        budgetSpent
        totalBudget
        budgetLeft
        daysLeft
        daysIntoFlight
        dailyAvgImpressions
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
